import{_ as t,H as a,f as i,i as n}from"./chunks/framework.DbTCwA-u.js";const h=JSON.parse('{"title":"Installation & Requirements","description":"Learn how to install EligiusNametag on your Paper or Folia server.","frontmatter":{"title":"Installation & Requirements","description":"Learn how to install EligiusNametag on your Paper or Folia server."},"headers":[],"relativePath":"installation.md","filePath":"installation.md"}'),o={name:"installation.md"};function s(r,e,l,d,m,u){return a(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="installation-requirements" tabindex="-1">Installation &amp; Requirements <a class="header-anchor" href="#installation-requirements" aria-label="Permalink to &quot;Installation &amp; Requirements&quot;">​</a></h1><p>EligiusNametag is a modern and powerful plugin. By leveraging the latest features of the Minecraft Text API and multi-threading, it requires an updated environment.</p><h2 id="📋-system-requirements" tabindex="-1">📋 System Requirements <a class="header-anchor" href="#📋-system-requirements" aria-label="Permalink to &quot;📋 System Requirements&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requirement</th><th>Minimum Version</th><th>Reason</th></tr></thead><tbody><tr><td><strong>Platform</strong></td><td>Paper 1.21 or Folia 1.21+</td><td>Strict use of <code>TEXT_DISPLAY</code> components and Brigadier commands.</td></tr><tr><td><strong>Java</strong></td><td>Java 21 LTS</td><td>Source code compiled in JDK 21 format.</td></tr></tbody></table><h2 id="📦-dependencies" tabindex="-1">📦 Dependencies <a class="header-anchor" href="#📦-dependencies" aria-label="Permalink to &quot;📦 Dependencies&quot;">​</a></h2><p>You must have the following plugins installed in your <code>plugins/</code> folder:</p><ol><li><strong>ProtocolLib</strong> <em>(Required)</em>: Used to send hologram packets invisibly without consuming physical TPS.</li><li><strong>Vault</strong> <em>(Optional)</em>: If you want to grant specific nametag designs depending on the user&#39;s rank (Admin, VIP, etc.).</li><li><strong>PlaceholderAPI</strong> <em>(Optional)</em>: To parse external variables such as stats, money, or clans in the nametags.</li><li><strong>ItemsAdder</strong> <em>(Optional)</em>: To display custom emojis in names.</li></ol><h2 id="🚀-installation-steps" tabindex="-1">🚀 Installation Steps <a class="header-anchor" href="#🚀-installation-steps" aria-label="Permalink to &quot;🚀 Installation Steps&quot;">​</a></h2><ol><li>Download the <code>EligiusNametag-1.x.x.jar</code> file from the <strong>Releases</strong> tab.</li><li>Copy the file into your server&#39;s <code>plugins/</code> directory.</li><li>Make sure you have <strong>ProtocolLib</strong> installed.</li><li>Start your server.</li><li>You will see the startup animation in the console with the Eligius MC cat confirming the plugin has hooked successfully.</li><li>Done! You can configure everything from <code>plugins/EligiusNametag/</code>.</li></ol>',9)])])}const p=t(o,[["render",s]]);export{h as __pageData,p as default};
